# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker.check_proof","kind":"function","src_hash":"965503df7af87a0f","in":{"base":"ProofTerm"},"out":{"base":"VerificationResult"},"spec":{"lhs":"check_proof(pro)","rhs":"mechanically verify that ``proof`` proves ``lhs \u2261 rhs``","over":{"base":"ProofTerm"},"name":"check_proof_correct"},"guarantee":"mechanically verify that ``proof`` proves ``lhs \u2261 rhs``","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker.check_proof_correct","statement":"Path(check_proof(x), mechanically verify that ``proof`` proves ``lhs \u2261 rhs``)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c1517f5b885cdb84"}
def check_proof(proof: ProofTerm, lhs: OTerm, rhs: OTerm,
                ctx: Optional[ProofContext] = None) -> VerificationResult:
    """Mechanically verify that ``proof`` proves ``lhs ≡ rhs``.

    This is DETERMINISTIC and TERMINATING.  No sampling.

    Parameters
    ----------
    proof : ProofTerm
        The proof term to check.
    lhs : OTerm
        Left-hand side of the equality.
    rhs : OTerm
        Right-hand side of the equality.
    ctx : ProofContext, optional
        Initial context (definitions, assumptions).

    Returns
    -------
    VerificationResult
        .valid is True iff the proof is accepted.
    """
    if ctx is None:
        ctx = ProofContext()

    start = time.monotonic()
    try:
        result = _check(proof, lhs, rhs, ctx)
    except _ProofError as e:
        result = VerificationResult(False, str(e))
    except RecursionError:
        result = VerificationResult(False, 'proof too deep (Python recursion limit)')
    elapsed = (time.monotonic() - start) * 1000
    result.time_ms = elapsed
    result.z3_calls = ctx.z3_calls
    return result


