def _check_sym(proof: Sym, lhs: OTerm, rhs: OTerm,
               ctx: ProofContext) -> VerificationResult:
    """Sym(p) proves lhs ≡ rhs by proving rhs ≡ lhs."""
    return _check(proof.proof, rhs, lhs, ctx)


