# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_cong","kind":"function","src_hash":"08a58c8b95e69ecb","in":{"base":"Cong","pred":"isinstance(lhs, OOp)"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_cong(pro)","rhs":"cong(f, [p\u2081, ..., p\u2099]) proves f(a\u2081,...,a\u2099) \u2261 f(b\u2081,...,b\u2099) given p\u1d62 proves a\u1d62 \u2261 b\u1d62","over":{"base":"Cong","pred":"isinstance(lhs, OOp)"},"name":"_check_cong_correct"},"guarantee":"cong(f, [p\u2081, ..., p\u2099]) proves f(a\u2081,...,a\u2099) \u2261 f(b\u2081,...,b\u2099) given p\u1d62 proves a\u1d62 \u2261 b\u1d62","fibers":[{"name":"OOp","pred":"isinstance(lhs, OOp)","path":{"lhs":"_check_cong(x)","rhs":"cong(f, [p\u2081, ..., p\u2099]) proves f(a\u2081,...,a\u2099) \u2261 f(b\u2081,...,b\u2099) given p\u1d62 proves a\u1d62 \u2261 b\u1d62","over":{"base":"OOp","pred":"isinstance(lhs, OOp)"},"name":"_check_cong_OOp_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_cong_OOp_correct","statement":"_check_cong satisfies spec on OOp inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"ed8e6cd255a57f92"}
def _check_cong(proof: Cong, lhs: OTerm, rhs: OTerm,
                ctx: ProofContext) -> VerificationResult:
    """Cong(f, [p₁, ..., pₙ]) proves f(a₁,...,aₙ) ≡ f(b₁,...,bₙ)
    given pᵢ proves aᵢ ≡ bᵢ.
    """
    # lhs and rhs must both be OOp with the same function name
    if not isinstance(lhs, OOp) or not isinstance(rhs, OOp):
        return _fail(f'cong: lhs or rhs is not an OOp')

    if lhs.name != proof.func or rhs.name != proof.func:
        return _fail(f'cong: function mismatch: '
                     f'lhs={lhs.name}, rhs={rhs.name}, proof={proof.func}')

    if len(lhs.args) != len(rhs.args):
        return _fail(f'cong: arity mismatch: '
                     f'lhs has {len(lhs.args)}, rhs has {len(rhs.args)}')

    if len(proof.arg_proofs) != len(lhs.args):
        return _fail(f'cong: {len(proof.arg_proofs)} proofs for '
                     f'{len(lhs.args)} arguments')

    max_depth = 0
    for i, (arg_proof, la, ra) in enumerate(
            zip(proof.arg_proofs, lhs.args, rhs.args)):
        result = _check(arg_proof, la, ra, ctx)
        if not result.valid:
            return _fail(f'cong: argument {i} failed: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'cong[{proof.func}]', depth=max_depth + 1)


