# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_wf_induction","kind":"function","src_hash":"e4f3074c7e434bb7","in":{"base":"WellFoundedInduction"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_wf_induction(pro)","rhs":"wellfoundedinduction: prove p(x) for all x by showing that p holds assuming p(y) for all y with measure(y) < measure(x)","over":{"base":"WellFoundedInduction"},"name":"_check_wf_induction_correct"},"guarantee":"wellfoundedinduction: prove p(x) for all x by showing that p holds assuming p(y) for all y with measure(y) < measure(x)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_wf_induction_correct","statement":"Path(_check_wf_induction(x), wellfoundedinduction: prove p(x) for all x by showing that p holds assuming p(y) for all y with measure(y) < measure(x))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f0500419b21c4703"}
def _check_wf_induction(proof: WellFoundedInduction, lhs: OTerm, rhs: OTerm,
                         ctx: ProofContext) -> VerificationResult:
    """WellFoundedInduction: prove P(x) for all x by showing that
    P holds assuming P(y) for all y with measure(y) < measure(x).

    The step proof must prove lhs ≡ rhs assuming the IH for all
    strictly smaller elements.
    """
    ih_label = f'WF_IH_{proof.measure}'
    ih_ctx = ctx.with_assumption(ih_label, lhs, rhs)

    step_result = _check(proof.step, lhs, rhs, ih_ctx)
    if not step_result.valid:
        return _fail(f'wf_induction step failed: {step_result.reason}')

    return _ok(f'wf_induction[μ={proof.measure}]',
               depth=step_result.proof_depth + 1,
               assumptions=[ih_label])


