# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._parse_z3_formula","kind":"function","src_hash":"643e0d93ec083539","in":{"base":"str"},"out":{"base":"Any"},"spec":{"lhs":"_parse_z3_formula(for)","rhs":"parse a simple formula string into a z3 expression","over":{"base":"str"},"name":"_parse_z3_formula_correct"},"guarantee":"parse a simple formula string into a z3 expression","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._parse_z3_formula_correct","statement":"Path(_parse_z3_formula(x), parse a simple formula string into a z3 expression)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"08a568830a55ee98"}
def _parse_z3_formula(formula: str, variables: Dict[str, Any]) -> Any:
    """Parse a simple formula string into a Z3 expression.

    Supports: ==, !=, <, <=, >, >=, +, -, *, and, or, not, implies,
    integer literals, variable references, forall, exists.
    """
    if not _HAS_Z3:
        return None

    formula = formula.strip()

    # Simple equality: a == b
    if formula.startswith('forall') or formula.startswith('exists'):
        return None  # QF only

    # Try direct eval with Z3 in scope
    try:
        local_ns = dict(variables)
        local_ns.update({
            'And': And, 'Or': Or, 'Not': Not, 'Implies': Implies,
            'Int': Int, 'Bool': Bool, 'IntVal': IntVal, 'BoolVal': BoolVal,
            'True': BoolVal(True), 'False': BoolVal(False),
        })
        result = eval(formula, {'__builtins__': {}}, local_ns)
        return result
    except Exception:
        pass

    # Fallback: try to build from simple patterns
    for op_str, z3_op in [(' == ', lambda a, b: a == b),
                          (' != ', lambda a, b: a != b),
                          (' <= ', lambda a, b: a <= b),
                          (' >= ', lambda a, b: a >= b),
                          (' < ', lambda a, b: a < b),
                          (' > ', lambda a, b: a > b)]:
        if op_str in formula:
            parts = formula.split(op_str, 1)
            if len(parts) == 2:
                left = _parse_z3_term(parts[0].strip(), variables)
                right = _parse_z3_term(parts[1].strip(), variables)
                if left is not None and right is not None:
                    return z3_op(left, right)

    return None


