# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._parse_z3_term","kind":"function","src_hash":"022fe18fa6900ad6","in":{"base":"str"},"out":{"base":"Any"},"spec":{"lhs":"_parse_z3_term(ter)","rhs":"parse a simple term into a z3 expression","over":{"base":"str"},"name":"_parse_z3_term_correct"},"guarantee":"parse a simple term into a z3 expression","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._parse_z3_term_correct","statement":"Path(_parse_z3_term(x), parse a simple term into a z3 expression)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"5c3ced8b37460d4a"}
def _parse_z3_term(term_str: str, variables: Dict[str, Any]) -> Any:
    """Parse a simple term into a Z3 expression."""
    if not _HAS_Z3:
        return None

    term_str = term_str.strip()

    if term_str in variables:
        return variables[term_str]

    try:
        return IntVal(int(term_str))
    except ValueError:
        pass

    # Simple arithmetic: a + b, a - b, a * b
    for op_str, op_fn in [('+', lambda a, b: a + b),
                          ('-', lambda a, b: a - b),
                          ('*', lambda a, b: a * b)]:
        if op_str in term_str:
            parts = term_str.rsplit(op_str, 1)
            if len(parts) == 2:
                left = _parse_z3_term(parts[0].strip(), variables)
                right = _parse_z3_term(parts[1].strip(), variables)
                if left is not None and right is not None:
                    return op_fn(left, right)

    return None


