# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_fiber_decomposition","kind":"function","src_hash":"705bad84f146791e","in":{"base":"FiberDecomposition"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_fiber_decomposition(pro)","rhs":"fiberdecomposition: prove on each fiber separately","over":{"base":"FiberDecomposition"},"name":"_check_fiber_decomposition_correct"},"guarantee":"fiberdecomposition: prove on each fiber separately","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_fiber_decomposition_correct","statement":"Path(_check_fiber_decomposition(x), fiberdecomposition: prove on each fiber separately)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fdc9fd2b8f253a65"}
def _check_fiber_decomposition(proof: FiberDecomposition,
                               lhs: OTerm, rhs: OTerm,
                               ctx: ProofContext) -> VerificationResult:
    """FiberDecomposition: prove on each fiber separately.

    Verify that each fiber proof is valid.  The global equality
    follows from the sheaf condition.
    """
    if not proof.fiber_proofs:
        return _fail('fiber_decomposition: no fibers')

    max_depth = 0
    for fiber_name, fiber_proof in proof.fiber_proofs.items():
        result = _check(fiber_proof, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'fiber {fiber_name}: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'fiber_decomposition ({len(proof.fiber_proofs)} fibers)',
               depth=max_depth + 1)


