# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_cech_gluing","kind":"function","src_hash":"8341e422ea14a47d","in":{"base":"CechGluing"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_cech_gluing(pro)","rhs":"cechgluing: glue local proofs via \u010dech cohomology","over":{"base":"CechGluing"},"name":"_check_cech_gluing_correct"},"guarantee":"cechgluing: glue local proofs via \u010dech cohomology","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_cech_gluing_correct","statement":"Path(_check_cech_gluing(x), cechgluing: glue local proofs via \u010dech cohomology)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"659d45dab56f4342"}
def _check_cech_gluing(proof: CechGluing, lhs: OTerm, rhs: OTerm,
                       ctx: ProofContext) -> VerificationResult:
    """CechGluing: glue local proofs via Čech cohomology.

    All local proofs and overlap proofs must be valid.
    H¹ = 0 (no obstructions) → global equivalence.
    """
    if not proof.local_proofs:
        return _fail('cech_gluing: no local proofs')

    max_depth = 0
    for i, local_p in enumerate(proof.local_proofs):
        result = _check(local_p, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'cech local[{i}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    for i, overlap_p in enumerate(proof.overlap_proofs):
        result = _check(overlap_p, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'cech overlap[{i}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'cech_gluing ({len(proof.local_proofs)} locals, '
               f'{len(proof.overlap_proofs)} overlaps)',
               depth=max_depth + 1)


