# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_let_proof","kind":"function","src_hash":"82f1fda854f144c5","in":{"base":"LetProof"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_let_proof(pro)","rhs":"letproof: bind an intermediate proof for reuse","over":{"base":"LetProof"},"name":"_check_let_proof_correct"},"guarantee":"letproof: bind an intermediate proof for reuse","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_let_proof_correct","statement":"Path(_check_let_proof(x), letproof: bind an intermediate proof for reuse)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"809ab587ddf17771"}
def _check_let_proof(proof: LetProof, lhs: OTerm, rhs: OTerm,
                     ctx: ProofContext) -> VerificationResult:
    """LetProof: bind an intermediate proof for reuse."""
    sub_r = _check(proof.sub_proof, proof.sub_lhs, proof.sub_rhs, ctx)
    if not sub_r.valid:
        return _fail(f'let: sub-proof failed: {sub_r.reason}')

    new_ctx = ctx.with_assumption(proof.label, proof.sub_lhs, proof.sub_rhs)
    body_r = _check(proof.body, lhs, rhs, new_ctx)
    if not body_r.valid:
        return _fail(f'let: body failed: {body_r.reason}')

    return _ok(f'let {proof.label}',
               depth=max(sub_r.proof_depth, body_r.proof_depth) + 1)


