# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_cases_split","kind":"function","src_hash":"e486703e3c9223cb","in":{"base":"CasesSplit"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_cases_split(pro)","rhs":"casessplit: prove by case analysis","over":{"base":"CasesSplit"},"name":"_check_cases_split_correct"},"guarantee":"casessplit: prove by case analysis","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_cases_split_correct","statement":"Path(_check_cases_split(x), casessplit: prove by case analysis)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"98c20d6ebc70e032"}
def _check_cases_split(proof: CasesSplit, lhs: OTerm, rhs: OTerm,
                       ctx: ProofContext) -> VerificationResult:
    """CasesSplit: prove by case analysis."""
    if not proof.cases:
        return _fail('cases_split: no cases provided')

    max_depth = 0
    for label, case_proof in proof.cases.items():
        result = _check(case_proof, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'case {label}: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'cases_split ({len(proof.cases)} cases)', depth=max_depth + 1)


