# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_ext","kind":"function","src_hash":"8d8ce233612d2dfa","in":{"base":"Ext","pred":"isinstance(lhs, OLam)"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_ext(pro)","rhs":"ext: extensionality \u2014 prove f \u2261 g by proving \u2200x","over":{"base":"Ext","pred":"isinstance(lhs, OLam)"},"name":"_check_ext_correct"},"guarantee":"ext: extensionality \u2014 prove f \u2261 g by proving \u2200x","fibers":[{"name":"OLam","pred":"isinstance(lhs, OLam)","path":{"lhs":"_check_ext(x)","rhs":"ext: extensionality \u2014 prove f \u2261 g by proving \u2200x","over":{"base":"OLam","pred":"isinstance(lhs, OLam)"},"name":"_check_ext_OLam_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_ext_OLam_correct","statement":"_check_ext satisfies spec on OLam inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"4c7e1a5a5f8ccab4"}
def _check_ext(proof: Ext, lhs: OTerm, rhs: OTerm,
               ctx: ProofContext) -> VerificationResult:
    """Ext: extensionality — prove f ≡ g by proving ∀x. f(x) ≡ g(x)."""
    # The body proof should prove f(var) ≡ g(var)
    x = OVar(proof.var)

    # If lhs/rhs are functions (OLam or OOp), apply them to x
    if isinstance(lhs, OLam) and isinstance(rhs, OLam):
        if len(lhs.params) == 1 and len(rhs.params) == 1:
            body_lhs = subst_in_term(lhs.body, lhs.params[0], x)
            body_rhs = subst_in_term(rhs.body, rhs.params[0], x)
        else:
            body_lhs = OOp('apply', (lhs, x))
            body_rhs = OOp('apply', (rhs, x))
    else:
        body_lhs = OOp('apply', (lhs, x))
        body_rhs = OOp('apply', (rhs, x))

    result = _check(proof.body_proof, body_lhs, body_rhs, ctx)
    if not result.valid:
        return _fail(f'ext: body proof failed: {result.reason}')

    return _ok(f'ext ∀{proof.var}', depth=result.proof_depth + 1)


