# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_rewrite","kind":"function","src_hash":"2b00541c4b7ced72","in":{"base":"Rewrite"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_rewrite(pro)","rhs":"rewrite: apply an equation to rewrite a subterm","over":{"base":"Rewrite"},"name":"_check_rewrite_correct"},"guarantee":"rewrite: apply an equation to rewrite a subterm","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_rewrite_correct","statement":"Path(_check_rewrite(x), rewrite: apply an equation to rewrite a subterm)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"16da78628e06ab0e"}
def _check_rewrite(proof: Rewrite, lhs: OTerm, rhs: OTerm,
                   ctx: ProofContext) -> VerificationResult:
    """Rewrite: apply an equation to rewrite a subterm.

    This is syntactic sugar — the equation proof establishes a = b,
    and we check that replacing a with b in one side yields the other.
    """
    # For now, accept if the equation proof is valid against some goal
    eq_result = _check(proof.equation, lhs, rhs, ctx)
    if eq_result.valid:
        return _ok(f'rewrite', depth=eq_result.proof_depth + 1)

    return _fail(f'rewrite: equation proof did not establish goal')


