# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_definitional","kind":"function","src_hash":"f324cee7e0563c96","in":{"base":"Definitional"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_definitional(pro)","rhs":"definitional: both sides normalize to the same term","over":{"base":"Definitional"},"name":"_check_definitional_correct"},"guarantee":"definitional: both sides normalize to the same term","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_definitional_correct","statement":"Path(_check_definitional(x), definitional: both sides normalize to the same term)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3c06e86ed0b5c27f"}
def _check_definitional(proof: Definitional, lhs: OTerm, rhs: OTerm,
                        ctx: ProofContext) -> VerificationResult:
    """Definitional: both sides normalize to the same term."""
    n_lhs = normalize_term(lhs)
    n_rhs = normalize_term(rhs)

    if terms_equal(n_lhs, n_rhs):
        return _ok('definitional equality', depth=ctx.depth)

    # Also try canonical forms
    if lhs.canon() == rhs.canon():
        return _ok('definitional equality (canon)', depth=ctx.depth)

    return _fail(f'definitional: {n_lhs.canon()[:30]} ≠ {n_rhs.canon()[:30]}')


