# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | e1326de83ca4bd44  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_refinement_descent","kind":"function","src_hash":"529e706c5a4006dd","in":{"base":"RefinementDescent"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_refinement_descent(pro)","rhs":"refinementdescent: \u010dech descent by refinement-type fibers","over":{"base":"RefinementDescent"},"name":"_check_refinement_descent_correct"},"guarantee":"refinementdescent: \u010dech descent by refinement-type fibers","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_refinement_descent_correct","statement":"Path(_check_refinement_descent(x), refinementdescent: \u010dech descent by refinement-type fibers)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e1326de83ca4bd44"}
def _check_refinement_descent(proof: RefinementDescent,
                              lhs: OTerm, rhs: OTerm,
                              ctx: ProofContext) -> VerificationResult:
    """RefinementDescent: Čech descent by refinement-type fibers.

    Unlike plain Descent (string-labeled fibers), this checks:

    1. Each fiber proof under a RESTRICTED context: the proof is
       verified with the refinement predicate φ added as an assumption.
       This means the fiber proof can use the predicate as a hypothesis.

    2. Overlap proofs are checked under the conjunction φ_a ∧ φ_b.
       Z3-empty overlaps (proven unsatisfiable) need no proof.

    3. Exhaustiveness: the disjunction ∨φᵢ must cover the domain.
       - If all predicates are Z3-decidable: verified by Z3.
       - Otherwise: trusted (marked 'assumed' by the proof term).

    Soundness argument: if ∀i. (φᵢ ⊢ lhs ≡ rhs) and the φᵢ cover
    the domain (∨φᵢ = True) and local proofs agree on overlaps,
    then lhs ≡ rhs globally.  This is the Čech descent theorem
    applied to the refinement lattice.
    """
    if not proof.fiber_proofs:
        return _fail('refinement_descent: no fiber proofs')

    if not proof.fiber_predicates:
        return _fail('refinement_descent: no fiber predicates')

    # Step 1: Verify exhaustiveness of the cover
    exhaustiveness = proof.exhaustiveness
    if exhaustiveness not in ('z3_proved', 'assumed'):
        # Try Z3 verification ourselves
        try:
            from cctt.proof_theory.predicates import (
                RefinementCover, parse_predicate, _z3_check_valid, POr,
            )
            all_preds = [parse_predicate(p) for p in proof.fiber_predicates.values()]
            if all_preds:
                disj = POr(tuple(all_preds)) if len(all_preds) > 1 else all_preds[0]
                if _z3_check_valid(disj, proof.var_sorts):
                    exhaustiveness = 'z3_proved'
                else:
                    exhaustiveness = 'assumed'
        except ImportError:
            exhaustiveness = 'assumed'

    max_depth = 0

    # Step 2: Check each fiber proof under its refinement hypothesis
    for fiber_name, fiber_proof in proof.fiber_proofs.items():
        if fiber_name not in proof.fiber_predicates:
            return _fail(f'refinement_descent: fiber {fiber_name} has no predicate')

        pred_str = proof.fiber_predicates[fiber_name]

        # Add the refinement predicate as an assumption in the context.
        # This is the key semantic difference from plain Descent:
        # the fiber proof can USE the predicate as a hypothesis.
        #
        # We represent the assumption as:
        #   label = "refine_φ"
        #   assumed_lhs/rhs = the predicate as an OAbstract
        refined_ctx = ctx.with_assumption(
            f'refine_{fiber_name}',
            OAbstract(f'{proof.bound_var}:{pred_str}', ()),
            OAbstract('True', ()),
        )

        result = _check(fiber_proof, lhs, rhs, refined_ctx)
        if not result.valid:
            return _fail(f'refinement_descent fiber[{fiber_name}] '
                         f'(under {pred_str[:40]}): {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    # Step 3: Check overlap proofs for non-empty overlaps
    for (fa, fb), overlap_proof in proof.overlap_proofs.items():
        pred_a = proof.fiber_predicates.get(fa, 'True')
        pred_b = proof.fiber_predicates.get(fb, 'True')

        # Check if the overlap is Z3-provably empty
        try:
            from cctt.proof_theory.predicates import (
                parse_predicate, PAnd, _z3_check_unsat,
            )
            intersection = PAnd((parse_predicate(pred_a), parse_predicate(pred_b)))
            is_empty = _z3_check_unsat(intersection, proof.var_sorts)
            if is_empty is True:
                continue  # Empty overlap — no proof needed
        except ImportError:
            pass

        # Non-empty (or unknown) overlap: check the compatibility proof
        # under the conjunction of both predicates
        overlap_ctx = ctx.with_assumption(
            f'refine_{fa}',
            OAbstract(f'{proof.bound_var}:{pred_a}', ()),
            OAbstract('True', ()),
        )
        overlap_ctx = overlap_ctx.with_assumption(
            f'refine_{fb}',
            OAbstract(f'{proof.bound_var}:{pred_b}', ()),
            OAbstract('True', ()),
        )

        result = _check(overlap_proof, lhs, rhs, overlap_ctx)
        if not result.valid:
            return _fail(f'refinement_descent overlap[{fa}∩{fb}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    # Step 4: Check for missing fibers (every predicate should have a proof)
    for fiber_name in proof.fiber_predicates:
        if fiber_name not in proof.fiber_proofs:
            return _fail(f'refinement_descent: missing proof for fiber {fiber_name}')

    exh_tag = f', exhaustive={exhaustiveness}' if exhaustiveness else ''
    overlap_count = len(proof.overlap_proofs)
    return _ok(f'refinement_descent ({len(proof.fiber_proofs)} fibers, '
               f'{overlap_count} overlaps{exh_tag})',
               depth=max_depth + 1)


