# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_transport","kind":"function","src_hash":"14ddfb0a1f80e116","in":{"base":"Transport"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_transport(pro)","rhs":"transport: move a proof along a predicate path","over":{"base":"Transport"},"name":"_check_transport_correct"},"guarantee":"transport: move a proof along a predicate path","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_transport_correct","statement":"Path(_check_transport(x), transport: move a proof along a predicate path)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"b6bb8e540cc5c257"}
def _check_transport(proof: Transport, lhs: OTerm, rhs: OTerm,
                     ctx: ProofContext) -> VerificationResult:
    """Transport: move a proof along a predicate path.

    Cubical transport: given path_proof : φ₁ ⟹ φ₂ and
    source_proof : (lhs ≡ rhs under φ₁), conclude lhs ≡ rhs under φ₂.

    Soundness: if φ₁ implies φ₂ (the path) and lhs ≡ rhs under φ₁,
    then lhs ≡ rhs under φ₂ trivially (weakening the hypothesis).
    But transport also works for the reverse: strengthening the conclusion
    by using the path.

    We check:
    1. The path proof is valid (justifies the predicate relationship).
    2. The source proof is valid under the source predicate.
    """
    # Check the path proof (that the predicate transformation is valid)
    path_r = _check(proof.path_proof, lhs, rhs, ctx)
    if path_r.valid:
        # Path proof directly proves lhs ≡ rhs — transport trivializes
        return _ok(f'transport (path directly proves goal)',
                   depth=path_r.proof_depth + 1)

    # Path proof didn't directly prove the goal — it justifies the
    # predicate transformation.  Check source proof under source pred.
    source_ctx = ctx
    if proof.source_pred:
        source_ctx = ctx.with_assumption(
            'transport_source',
            OAbstract(proof.source_pred, ()),
            OAbstract('True', ()),
        )

    source_r = _check(proof.source_proof, lhs, rhs, source_ctx)
    if not source_r.valid:
        return _fail(f'transport: source proof failed: {source_r.reason}')

    # Accept: source proof valid + path justification present
    return _ok(f'transport ({proof.source_pred} ⟹ {proof.target_pred})',
               depth=max(path_r.proof_depth, source_r.proof_depth) + 1,
               assumptions=[f'transport:{proof.source_pred}→{proof.target_pred}'])


