# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_hcomp","kind":"function","src_hash":"bc10b598cb59d025","in":{"base":"HComp"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_hcomp(pro)","rhs":"hcomp: homogeneous composition (cubical hcomp)","over":{"base":"HComp"},"name":"_check_hcomp_correct"},"guarantee":"hcomp: homogeneous composition (cubical hcomp)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_hcomp_correct","statement":"Path(_check_hcomp(x), hcomp: homogeneous composition (cubical hcomp))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2a018828303ecca0"}
def _check_hcomp(proof: HComp, lhs: OTerm, rhs: OTerm,
                 ctx: ProofContext) -> VerificationResult:
    """HComp: homogeneous composition (cubical hcomp).

    Fill a box of partial proofs.  Each face proof must be valid.
    If a base proof is given, it must also be valid.

    The cubical interpretation: given a partial cube with specified
    boundary, the Kan condition guarantees a filler exists.
    Our checker verifies all faces are valid proofs, then accepts
    the composite.

    Soundness: if every face of the cube proves lhs ≡ rhs, then
    the filler does too (by the Kan condition of the path type).
    """
    if not proof.faces:
        return _fail('hcomp: no faces provided')

    max_depth = 0

    for face_name, face_proof in proof.faces.items():
        result = _check(face_proof, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'hcomp face[{face_name}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    if proof.base:
        base_r = _check(proof.base, lhs, rhs, ctx)
        if not base_r.valid:
            return _fail(f'hcomp base: {base_r.reason}')
        max_depth = max(max_depth, base_r.proof_depth)

    return _ok(f'hcomp ({len(proof.faces)} faces)',
               depth=max_depth + 1)


