# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_glue_path","kind":"function","src_hash":"995054c2220297f0","in":{"base":"GluePath"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_glue_path(pro)","rhs":"gluepath: glue local cubical paths via \u010dech descent","over":{"base":"GluePath"},"name":"_check_glue_path_correct"},"guarantee":"gluepath: glue local cubical paths via \u010dech descent","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_glue_path_correct","statement":"Path(_check_glue_path(x), gluepath: glue local cubical paths via \u010dech descent)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f24c2cb60a39e6f7"}
def _check_glue_path(proof: GluePath, lhs: OTerm, rhs: OTerm,
                     ctx: ProofContext) -> VerificationResult:
    """GluePath: glue local cubical paths via Čech descent.

    This is the combined cubical + cohomological rule:
    1. Each fiber's local path proof is checked under its refinement
       predicate (like RefinementDescent).
    2. Overlap path proofs are checked under the conjunction of
       both fiber predicates.
    3. The result is a global path proof.

    This is strictly more powerful than plain Descent because:
    - Fibers get refinement hypotheses (like RefinementDescent)
    - The proofs are paths (parameterized), not just equalities
    - The gluing uses the cubical Kan condition, not just transitivity
    """
    if not proof.local_paths:
        return _fail('glue_path: no local paths')

    max_depth = 0

    # Check each local path under its refinement hypothesis
    for fiber_name, local_proof in proof.local_paths.items():
        fiber_ctx = ctx
        pred_str = proof.fiber_predicates.get(fiber_name, '')
        if pred_str:
            fiber_ctx = ctx.with_assumption(
                f'glue_fiber_{fiber_name}',
                OAbstract(pred_str, ()),
                OAbstract('True', ()),
            )

        result = _check(local_proof, lhs, rhs, fiber_ctx)
        if not result.valid:
            return _fail(f'glue_path fiber[{fiber_name}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    # Check overlap path proofs
    for (fa, fb), overlap_proof in proof.overlap_paths.items():
        pred_a = proof.fiber_predicates.get(fa, '')
        pred_b = proof.fiber_predicates.get(fb, '')

        # Try Z3 emptiness check on overlap
        try:
            from cctt.proof_theory.predicates import (
                parse_predicate, PAnd, _z3_check_unsat,
            )
            if pred_a and pred_b:
                intersection = PAnd((parse_predicate(pred_a),
                                     parse_predicate(pred_b)))
                if _z3_check_unsat(intersection, {}):
                    continue  # Empty overlap
        except ImportError:
            pass

        overlap_ctx = ctx
        if pred_a:
            overlap_ctx = overlap_ctx.with_assumption(
                f'glue_fiber_{fa}',
                OAbstract(pred_a, ()),
                OAbstract('True', ()),
            )
        if pred_b:
            overlap_ctx = overlap_ctx.with_assumption(
                f'glue_fiber_{fb}',
                OAbstract(pred_b, ()),
                OAbstract('True', ()),
            )

        result = _check(overlap_proof, lhs, rhs, overlap_ctx)
        if not result.valid:
            return _fail(f'glue_path overlap[{fa}∩{fb}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'glue_path[{proof.cover_name}] '
               f'({len(proof.local_paths)} fibers, '
               f'{len(proof.overlap_paths)} overlaps)',
               depth=max_depth + 1)


