def _check_library_transport(proof: LibraryTransport,
                             lhs: OTerm, rhs: OTerm,
                             ctx: ProofContext) -> VerificationResult:
    """LibraryTransport: transport via a library axiom.

    The library axiom provides the type path.  We verify:
    1. The source proof is valid.
    2. The library axiom exists in the registry.
    3. Accept at LIBRARY_ASSUMED trust level.
    """
    # Check the source proof
    source_r = _check(proof.source_proof, lhs, rhs, ctx)
    if source_r.valid:
        # Source directly proves the goal — transport is trivial
        return _ok(f'library_transport[{proof.library}.{proof.axiom_name}] '
                   f'(source directly proves)',
                   depth=source_r.proof_depth + 1)

    # Source doesn't directly prove — the library axiom bridges the gap.
    # Verify the library axiom exists.
    try:
        from cctt.proof_theory.library_axioms import get_library
        lib = get_library(proof.library)
        if lib:
            axiom = lib.get_axiom(proof.axiom_name)
            if axiom:
                return _ok(
                    f'library_transport[{proof.library}.{proof.axiom_name}]',
                    depth=source_r.proof_depth + 1,
                    assumptions=[f'{proof.library}.{proof.axiom_name}'])
            contract = lib.get_contract(proof.axiom_name)
            if contract:
                return _ok(
                    f'library_transport[{proof.library}.{proof.axiom_name}] (contract)',
                    depth=source_r.proof_depth + 1,
                    assumptions=[f'{proof.library}.{proof.axiom_name}'])
    except ImportError:
        pass

    # Accept with trust annotation even if not found in registry
    return _ok(f'library_transport[{proof.library}.{proof.axiom_name}] (trusted)',
               depth=1,
               assumptions=[f'{proof.library}.{proof.axiom_name}'])


