def _check_library_axiom_proof(proof, lhs: OTerm, rhs: OTerm,
                               ctx: ProofContext) -> VerificationResult:
    """LibraryAxiom: accept a library axiom at LIBRARY_ASSUMED trust.

    The axiom is EXPLICITLY TRUSTED — not machine-checked.
    We verify the axiom exists in the registry if available,
    then accept at LIBRARY_ASSUMED level with full provenance.
    """
    try:
        from cctt.proof_theory.library_axioms import get_library
        lib = get_library(proof.library)
        if lib:
            axiom = lib.get_axiom(proof.axiom_name)
            if axiom:
                return _ok(
                    f'🟠 library_axiom[{proof.library}.{proof.axiom_name}]: '
                    f'{axiom.statement[:50]}',
                    depth=ctx.depth,
                    assumptions=[f'{proof.library}.{proof.axiom_name}'])
    except ImportError:
        pass

    # Accept even without registry — trust is explicit
    return _ok(f'🟠 library_axiom[{proof.library}.{proof.axiom_name}]',
               depth=ctx.depth,
               assumptions=[f'{proof.library}.{proof.axiom_name}'])


