# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.checker._check_library_contract_proof","kind":"function","src_hash":"f594a0bd117d2202","in":{"base":"Any"},"out":{"base":"VerificationResult"},"spec":{"lhs":"_check_library_contract_proof(pro)","rhs":"librarycontract: accept a library contract with precondition proofs","over":{"base":"Any"},"name":"_check_library_contract_proof_correct"},"guarantee":"librarycontract: accept a library contract with precondition proofs","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.checker._check_library_contract_proof_correct","statement":"Path(_check_library_contract_proof(x), librarycontract: accept a library contract with precondition proofs)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"05ee8701bcbe5be3"}
def _check_library_contract_proof(proof, lhs: OTerm, rhs: OTerm,
                                  ctx: ProofContext) -> VerificationResult:
    """LibraryContract: accept a library contract with precondition proofs.

    Checks that all precondition proofs are valid, then accepts
    the postcondition at LIBRARY_ASSUMED trust level.
    """
    max_depth = 0

    # Check all precondition proofs
    for pre_name, pre_proof in proof.precondition_proofs.items():
        # Precondition proofs are checked against a trivially true goal
        # (they prove that a precondition holds, not lhs ≡ rhs)
        result = _check(pre_proof, lhs, rhs, ctx)
        if not result.valid:
            return _fail(f'library_contract[{proof.library}.{proof.function_name}] '
                         f'precondition[{pre_name}]: {result.reason}')
        max_depth = max(max_depth, result.proof_depth)

    return _ok(f'🟠 library_contract[{proof.library}.{proof.function_name}]: '
               f'{proof.postcondition[:50]}',
               depth=max_depth + 1,
               assumptions=[f'{proof.library}.{proof.function_name}'])
